contracts/worldcupsweep/WorldCup2026Swee.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "https://github.com/OpenZeppelin/openzeppelin-contracts/blob/v5.4.0/contracts/token/ERC721/extensions/ERC721Enumerable.sol";
import "https://github.com/OpenZeppelin/openzeppelin-contracts/blob/v5.4.0/contracts/access/Ownable.sol";
import "https://github.com/OpenZeppelin/openzeppelin-contracts/blob/v5.4.0/contracts/utils/Strings.sol";
import "https://github.com/OpenZeppelin/openzeppelin-contracts/blob/v5.4.0/contracts/utils/ReentrancyGuard.sol";

// Optional mint interface for marketplace compatibility
interface IMintable {
    function mintPrice() external view returns (uint256);
    function mintableCount(address account) external view returns (uint256);
    function mint(uint256 mintCount) external payable;
}

contract WorldCupSweepstakeNFT is ERC721Enumerable, Ownable, IMintable, ReentrancyGuard {
    using Strings for uint256;

    uint256 public immutable MAX_SUPPLY;
    uint256 public mintPriceVar;
    uint256 public currentTokenId;

    bool public paused;
    bool public revealed;

    string public placeholderURI;
    string public revealedBaseURI;

    // tokenId => random metadata index
    mapping(uint256 => uint256) private tokenToMetadataIndex;

    // Tracks remaining metadata indices for random assignment
    uint256[] private availableMetadataIndices;
    uint256 private availableMetadataCount;

    // Winners
    bool public winnersCommitted;
    bool public payoutComplete;

    uint256 public firstPlaceTokenId;
    uint256 public secondPlaceTokenId;
    uint256 public thirdPlaceTokenId;

    address public firstPlaceRecipient;
    address public secondPlaceRecipient;
    address public thirdPlaceRecipient;

    event Mint(address indexed minter, uint256 count, uint256 value);
    event MintingToggled(bool paused);
    event Revealed(string revealedBaseURI);
    event PlaceholderURIUpdated(string newPlaceholderURI);
    event RevealedBaseURIUpdated(string newRevealedBaseURI);
    event WinnersCommitted(
        uint256 indexed firstPlaceTokenId,
        uint256 indexed secondPlaceTokenId,
        uint256 indexed thirdPlaceTokenId,
        address firstPlaceRecipient,
        address secondPlaceRecipient,
        address thirdPlaceRecipient
    );
    event PayoutExecuted(
        uint256 totalPayout,
        uint256 firstPrize,
        uint256 secondPrize,
        uint256 thirdPrize
    );

    constructor(
        string memory name_,
        string memory symbol_,
        uint256 maxSupply_,
        uint256 mintPrice_,
        string memory placeholderURI_,
        string memory revealedBaseURI_
    ) ERC721(name_, symbol_) Ownable(msg.sender) {
        require(maxSupply_ > 0, "Max supply must be > 0");

        MAX_SUPPLY = maxSupply_;
        mintPriceVar = mintPrice_;
        placeholderURI = placeholderURI_;
        revealedBaseURI = revealedBaseURI_;

        availableMetadataIndices = new uint256[](maxSupply_);
        for (uint256 i = 0; i < maxSupply_; i++) {
            availableMetadataIndices[i] = i + 1;
        }
        availableMetadataCount = maxSupply_;
    }

    function mintableCount(address) external view override returns (uint256) {
        if (paused) return 0;
        return availableMetadataCount;
    }

    function mintPrice() external view override returns (uint256) {
        return mintPriceVar;
    }

    function toggleMinting() external onlyOwner {
        paused = !paused;
        emit MintingToggled(paused);
    }

    function setMintPrice(uint256 newPrice) external onlyOwner {
        mintPriceVar = newPrice;
    }

    function setPlaceholderURI(string calldata newPlaceholderURI) external onlyOwner {
        placeholderURI = newPlaceholderURI;
        emit PlaceholderURIUpdated(newPlaceholderURI);
    }

    function setRevealedBaseURI(string calldata newRevealedBaseURI) external onlyOwner {
        require(!revealed, "Already revealed");
        revealedBaseURI = newRevealedBaseURI;
        emit RevealedBaseURIUpdated(newRevealedBaseURI);
    }

    function reveal() external onlyOwner {
        require(!revealed, "Already revealed");
        revealed = true;
        emit Revealed(revealedBaseURI);
    }

    function mint(uint256 mintCount) external payable override nonReentrant {
        require(!paused, "Minting is paused");
        require(mintCount > 0, "Mint count must be > 0");
        require(availableMetadataCount >= mintCount, "Exceeds available NFTs");
        require(currentTokenId + mintCount <= MAX_SUPPLY, "Exceeds max supply");
        require(msg.value >= mintCount * mintPriceVar, "Insufficient payment");

        for (uint256 i = 0; i < mintCount; i++) {
            uint256 tokenId = ++currentTokenId;
            _safeMint(msg.sender, tokenId);

            uint256 randomIndex = _getRandomMetadataIndex(i);
            tokenToMetadataIndex[tokenId] = availableMetadataIndices[randomIndex];

            // remove used index
            availableMetadataIndices[randomIndex] = availableMetadataIndices[availableMetadataCount - 1];
            availableMetadataIndices.pop();
            availableMetadataCount--;
        }

        emit Mint(msg.sender, mintCount, msg.value);
    }

function _getRandomMetadataIndex(uint256 nonce) internal view returns (uint256) {
    require(availableMetadataCount > 0, "No metadata indices available");

    uint256 random = uint256(
        keccak256(
            abi.encodePacked(
                block.timestamp,
                blockhash(block.number - 1),
                msg.sender,
                currentTokenId,
                availableMetadataCount,
                nonce
            )
        )
    );

    return random % availableMetadataCount;
}

    function tokenURI(uint256 tokenId) public view override returns (string memory) {
        require(_ownerOf(tokenId) != address(0), "URI query for nonexistent token");

        if (!revealed) {
            return placeholderURI;
        }

        uint256 metadataIndex = tokenToMetadataIndex[tokenId];
        require(metadataIndex != 0, "Metadata not assigned");

        return string(
            abi.encodePacked(
                revealedBaseURI,
                "/",
                metadataIndex.toString(),
                ".json"
            )
        );
    }

    function metadataIndexOf(uint256 tokenId) external view returns (uint256) {
        require(_ownerOf(tokenId) != address(0), "Query for nonexistent token");
        return tokenToMetadataIndex[tokenId];
    }

    function commitWinners(
        uint256 _firstPlaceTokenId,
        uint256 _secondPlaceTokenId,
        uint256 _thirdPlaceTokenId
    ) external onlyOwner {
        require(revealed, "Reveal first");
        require(!winnersCommitted, "Winners already committed");

        require(_ownerOf(_firstPlaceTokenId) != address(0), "First place token does not exist");
        require(_ownerOf(_secondPlaceTokenId) != address(0), "Second place token does not exist");
        require(_ownerOf(_thirdPlaceTokenId) != address(0), "Third place token does not exist");

        require(
            _firstPlaceTokenId != _secondPlaceTokenId &&
            _firstPlaceTokenId != _thirdPlaceTokenId &&
            _secondPlaceTokenId != _thirdPlaceTokenId,
            "Winner token IDs must be unique"
        );

        firstPlaceTokenId = _firstPlaceTokenId;
        secondPlaceTokenId = _secondPlaceTokenId;
        thirdPlaceTokenId = _thirdPlaceTokenId;

        // Snapshot recipients at commit time
        firstPlaceRecipient = ownerOf(_firstPlaceTokenId);
        secondPlaceRecipient = ownerOf(_secondPlaceTokenId);
        thirdPlaceRecipient = ownerOf(_thirdPlaceTokenId);

        winnersCommitted = true;

        emit WinnersCommitted(
            _firstPlaceTokenId,
            _secondPlaceTokenId,
            _thirdPlaceTokenId,
            firstPlaceRecipient,
            secondPlaceRecipient,
            thirdPlaceRecipient
        );
    }

    function payout() external onlyOwner nonReentrant {
        require(winnersCommitted, "Winners not committed");
        require(!payoutComplete, "Payout already completed");

        uint256 totalBalance = address(this).balance;
        require(totalBalance > 0, "No ETN to payout");

        uint256 firstPrize = (totalBalance * 70) / 100;
        uint256 secondPrize = (totalBalance * 20) / 100;
        uint256 thirdPrize = totalBalance - firstPrize - secondPrize; // avoids rounding dust

        payoutComplete = true;

        (bool success1, ) = payable(firstPlaceRecipient).call{value: firstPrize}("");
        require(success1, "First place payout failed");

        (bool success2, ) = payable(secondPlaceRecipient).call{value: secondPrize}("");
        require(success2, "Second place payout failed");

        (bool success3, ) = payable(thirdPlaceRecipient).call{value: thirdPrize}("");
        require(success3, "Third place payout failed");

        emit PayoutExecuted(totalBalance, firstPrize, secondPrize, thirdPrize);
    }

    receive() external payable {}
}

